source.linear:
def linear(x, w, b, ctx=None):
    y = x @ w.T + b
    if ctx is not None:
        ctx.append([linear_backward, [y, x, w, b]])
    return y

source.relu:
def relu(x, ctx=None):
    y = x.clamp(min=0).clone()
    if ctx is not None:
        ctx.append([relu_backward, [y, x]])
    return y
